# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import sqlite3
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

# Database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users (email TEXT, token TEXT)''')
    conn.commit()
    conn.close()

# Function to generate a token and send an email
def send_reset_email(email):
    token = secrets.token_hex(16)
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''INSERT OR REPLACE INTO users (email, token) VALUES (?, ?)''', (email, token))
    conn.commit()
    conn.close()

    # Email setup
    sender_email = "your-email@example.com"
    receiver_email = email
    password = "your-email-password"

    message = MIMEText(f"Click this link to reset your password: http://yourdomain.com/reset?token={token}")
    message["Subject"] = "Password Reset Request"
    message["From"] = sender_email
    message["To"] = receiver_email

    # Send email
    with smtplib.SMTP_SSL("smtp.example.com", 465) as server:
        server.login(sender_email, password)
        server.sendmail(sender_email, receiver_email, message.as_string())

# Flask endpoint for password reset request
@app.route('/reset-request', methods=['POST'])
def reset_request():
    data = request.json
    email = data.get('email')
    if not email:
        return jsonify({"error": "Email is required"}), 400

    send_reset_email(email)
    return jsonify({"message": "Reset link has been sent to your email."}), 200

if __name__ == '__main__':
    init_db()
    app.run(debug=True)